var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"이곳이 의뢰인의 저택…. 소문대로 엄청나네요.","JPN":"こちらが依頼人の邸宅……噂どおり、すごいですね。","ENG":"So this is the client's mansion... It's massive, just like the rumors said it was.","TWN":"這裡就是委託人的豪宅…正如傳聞，果然奢華。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우와… 우리 사무소와는 비교도 안 되잖아…?","JPN":"うわ……僕たちの事務所とは比べ物にならないな……","ENG":"Wow... Our office is tiny compared to here...!","TWN":"哇…我們事務所根本沒法比啊…？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"당연하지. 아가씨는 이 동네 최고 부자거든!","JPN":"当然でしょ？　お嬢様はこの街で随一のお金持ちなんだから！","ENG":"Of course it is. Our lady is the richest in town!","TWN":"當然。小姐是這個地方最富有的人！"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"내가 먹을 간식도 매일 따로 준비해 주신다구~","JPN":"アタシのおやつも毎日用意してくれるし。","ENG":"She even prepares my own snacks every day!","TWN":"甚至每天都會另外為我準備零食～"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"그건 네가 하도 훔쳐먹으니까 그렇지.","JPN":"それはお前が盗み食いするからだろ？","ENG":"That's because you keep stealing hers.","TWN":"還不是因為你一直在偷吃。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"너 또 아가씨께 드릴 간식을 다 먹냐!","JPN":"お前、またお嬢様のおやつを横取りしたな！","ENG":"And just as I'm talking, you ate our lady's snacks again?!","TWN":"你又把要給小姐的零食都吃光了啊！"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"아얏! 먹는데 때리는 게 어딨어!","JPN":"イタっ！　食べてる時に殴るのはナシだよ～！","ENG":"Oww! Don't hit me when I'm eating!","TWN":"哎呀！吃東西的時候怎麼能打人？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"다들 모였군. 만나서 반갑다 탐정!","JPN":"みんな集まったようだな。会えて嬉しいぞ、探偵！","ENG":"You're all here. Nice to see you, Detective!","TWN":"看來都來了啊。很高興認識你們，兩位偵探！"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"어이 카일. 설마 저들이 날 모르진 않겠지?","JPN":"おい、カイル。この者たちに私を紹介する必要なあるか？","ENG":"Hey, Kyle. Don't tell me that they don’t know who I am.","TWN":"喂，凱爾。他們不會不認識我吧？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"설마 아가씨를 모를 정도로 무식한 사람들은 아닐 겁니다.","JPN":"まさか、お嬢様を知らないような無知な者ではないはずです。","ENG":"I don't believe anyone is ignorant enough to not know who you are, Miss Lin.","TWN":"我想她們不會無知到不認識小姐您。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"저분들도… 나름 탐정이니까요.","JPN":"この人たちも……一応は探偵ですから。","ENG":"They are... detectives still.","TWN":"畢竟那些人…也算是偵探。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어…? 카린과 똑 닮은 사람이잖아?!","JPN":"あれ……？　カリンとそっくりじゃないか！？","ENG":"Huh...? He looks just like Karin!","TWN":"呃…？和卡琳長得一模一樣？！"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우연이라기엔 성격이나 말투까지 비슷한데? 설마 숨겨둔 남동생이 있었던 거야?","JPN":"偶然にしては、性格や言葉使いも似ているぞ？　もしかして、隠してた弟がいたのか？","ENG":"Their personalities and way of speaking are so similar that it cannot be a coincidence. Hey, have you hidden your brother all these years?","TWN":"要說是巧合，性格和說話方式也太相似了吧？難道卡琳你還有個弟弟嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"뭐, 뭐라고요?!","JPN":"な、何ですって！？","ENG":"W-what?!","TWN":"什、什麼？！"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"실례되는 말을 아무렇지도 않게 하시는군요.","JPN":"失礼なことを平気で言うのですね。","ENG":"How brazen of you to make such rude remarks.","TWN":"竟然如此無禮。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_BOTH","text":{"KOREA":"도대체 제가 어딜 봐서 저 사람이랑 닮았다는 겁니까!","JPN":"いったいどこがこの人と似ていると言うのですか！","ENG":"In what world do I look like him?!","TWN":"我們才不像呢！"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"안 되겠습니다 아가씨. 저 사람들을 도저히 신용할 수 없군요.","JPN":"いけません、お嬢様。この人たちは信用できません。","ENG":"This will not do, Miss Lin. I do not trust those people one bit.","TWN":"不行，小姐。我實在無法相信那兩人。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"지금이라도 그냥 경찰을 부르는 게 어떻습니까?","JPN":"今からでも警察を呼びしましょうか？","ENG":"Shall I take the liberty to call the cops?","TWN":"要不還是直接報警吧？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"쓸데없는 소리는 금지하겠습니다.","JPN":"無駄口は禁止にします。","ENG":"I'll stop speaking nonsense.","TWN":"別說廢話了。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"이쪽은 시급한 임무를 수행하는 중이니 어서 차나 대접해 주시죠.","JPN":"こちらは急ぎの任務を遂行している最中です。さっさとお茶でも出してください。","ENG":"We are busy with urgent matters, so how about you serve us some tea?","TWN":"我們正在執行一項緊急任務，所以請快點給我們倒杯茶吧。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"상대방에게 실례되는 언행과 더불어 손님 접대도 0점이네요. 집사 실격입니다.","JPN":"失礼な態度に、おもてなしも0点ですね。執事失格です。","ENG":"In addition to being rude to your guests, you're poor at hospitality. You give butlers a bad name.","TWN":"不僅無禮，連接待客人也是0分。你這樣的人，不配當管家。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"괴도에게 놀아난 당신이야말로 탐정 실격이겠죠.","JPN":"怪盗に弄ばれたあなたこそ、探偵失格でしょう。","ENG":"And you give detectives a bad name by failing to catch the phantom thief.","TWN":"被怪盜玩弄於股掌之中的你才不配當偵探吧。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"어, 어떻게 그걸…?!","JPN":"ど、どうしてそれを……！？","ENG":"H-how did you know about that...?!","TWN":"你、你怎麼知道…？！"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};